#include "cc1101.h"
#include "driver/spi_master.h"
#include "driver/gpio.h"
#include "esp_log.h"

static const char *TAG = "CC1101";
static spi_device_handle_t spi;

esp_err_t cc1101_init() {
    spi_bus_config_t buscfg = {
        .miso_io_num = GPIO_MISO,
        .mosi_io_num = GPIO_MOSI,
        .sclk_io_num = GPIO_SCK,
        .quadwp_io_num = -1,
        .quadhd_io_num = -1,
        .max_transfer_sz = 64
    };

    spi_device_interface_config_t devcfg = {
        .clock_speed_hz = 500000, // 500kHz
        .mode = 0,
        .spics_io_num = GPIO_SS,
        .queue_size = 7,
    };

    ESP_LOGI(TAG, "Initializing SPI: SCK=%d, MISO=%d, MOSI=%d, SS=%d", GPIO_SCK, GPIO_MISO, GPIO_MOSI, GPIO_SS);
    esp_err_t ret = spi_bus_initialize(SPI2_HOST, &buscfg, SPI_DMA_CH_AUTO);
    if (ret != ESP_OK) return ret;

    ret = spi_bus_add_device(SPI2_HOST, &devcfg, &spi);
    if (ret != ESP_OK) return ret;

    cc1101_cmd_strobe(CC1101_SRES);
    vTaskDelay(pdMS_TO_TICKS(50));

    // Dummy read to clear anything
    cc1101_read_reg(CC1101_PARTNUM | CC1101_READ_BURST);

    uint8_t partnum = cc1101_read_reg(CC1101_PARTNUM | CC1101_READ_BURST);
    uint8_t version = cc1101_read_reg(CC1101_VERSION | CC1101_READ_BURST);

    ESP_LOGI(TAG, "CC1101 Partnum: 0x%02x, Version: 0x%02x", partnum, version);

    if (version == 0 || version == 0xFF) return ESP_FAIL;

    // Default configuration for SlowRF (OOK/ASK)
    gpio_config_t marker_conf = {
        .pin_bit_mask = (1ULL << GPIO_433MARKER),
        .mode = GPIO_MODE_INPUT,
        .pull_up_en = GPIO_PULLUP_ENABLE,
    };
    gpio_config(&marker_conf);
    vTaskDelay(pdMS_TO_TICKS(10));
    bool is_433 = (gpio_get_level(GPIO_433MARKER) == 0);
    ESP_LOGI(TAG, "Detected Frequency: %s MHz", is_433 ? "433" : "868");

    // Common SlowRF Setup (ASK, ~2.4k Baud, etc.)
    cc1101_write_reg(0x02, 0x0D); // IOCFG0: GDO0 Serial Data Output
    cc1101_write_reg(0x00, 0x2E); // IOCFG2: GDO2 High Impedance
    cc1101_write_reg(0x08, 0x32); // PKTCTRL0: Asynchronous Serial Mode
    cc1101_write_reg(0x0B, 0x06); // FSCTRL1
    cc1101_write_reg(0x0C, 0x00); // FSCTRL0

    if (is_433) {
        cc1101_write_reg(0x0D, 0x10); // FREQ2
        cc1101_write_reg(0x0E, 0xB1); // FREQ1
        cc1101_write_reg(0x0F, 0x3B); // FREQ0
    } else {
        cc1101_write_reg(0x0D, 0x21); // FREQ2
        cc1101_write_reg(0x0E, 0x62); // FREQ1
        cc1101_write_reg(0x0F, 0x76); // FREQ0
    }

    cc1101_write_reg(0x10, 0x58); // MDMCFG4: BW 325kHz
    cc1101_write_reg(0x11, 0x93); // MDMCFG3
    cc1101_write_reg(0x12, 0x30); // MDMCFG2: ASK/OOK, No sync
    cc1101_write_reg(0x13, 0x22); // MDMCFG1
    cc1101_write_reg(0x14, 0xF8); // MDMCFG0
    cc1101_write_reg(0x15, 0x15); // DEVIATN
    cc1101_write_reg(0x18, 0x18); // MCSM0
    cc1101_write_reg(0x19, 0x16); // FOCCFG
    cc1101_write_reg(0x1A, 0x6C); // BSCFG
    cc1101_write_reg(0x1B, 0x03); // AGCCTRL2
    cc1101_write_reg(0x1C, 0x40); // AGCCTRL1
    cc1101_write_reg(0x1D, 0x91); // AGCCTRL0
    cc1101_write_reg(0x21, 0x56); // FREND1
    cc1101_write_reg(0x22, 0x11); // FREND0: ASK/OOK use PATABLE[1] for '1'
    cc1101_write_reg(0x23, 0xE9); // FSCAL3
    cc1101_write_reg(0x24, 0x2A); // FSCAL2
    cc1101_write_reg(0x25, 0x00); // FSCAL1
    cc1101_write_reg(0x26, 0x1F); // FSCAL0

    // PATABLE: [0]=0x00 (for '0'), [1]=0xC0 (for '1')
    uint8_t patable[] = {0x00, 0xC0};
    cc1101_write_burst(0x3E, patable, 2);


    cc1101_set_rx_mode();

    return ESP_OK;
}

void cc1101_set_rx_mode() {
    cc1101_cmd_strobe(CC1101_SIDLE);
    cc1101_write_reg(0x02, 0x0D); // IOCFG0: GDO0 Serial Data Output
    gpio_set_direction(GPIO_GDO0, GPIO_MODE_INPUT);
    cc1101_cmd_strobe(CC1101_SRX);
}

void cc1101_set_tx_mode() {
    cc1101_cmd_strobe(CC1101_SIDLE);
    cc1101_write_reg(0x02, 0x0D); // IOCFG0: GDO0 Serial Data Input (actually 0x0D is same pin but CC1101 will use it as input in TX)
    gpio_set_direction(GPIO_GDO0, GPIO_MODE_OUTPUT);
    cc1101_cmd_strobe(CC1101_STX);
}

void cc1101_set_idle_mode() {
    cc1101_cmd_strobe(CC1101_SIDLE);
}

#include "rom/ets_sys.h"

static void fs20_send_bit(int bit) {
    if (bit) {
        gpio_set_level(GPIO_GDO0, 1);
        ets_delay_us(600);
        gpio_set_level(GPIO_GDO0, 0);
        ets_delay_us(600);
    } else {
        gpio_set_level(GPIO_GDO0, 1);
        ets_delay_us(400);
        gpio_set_level(GPIO_GDO0, 0);
        ets_delay_us(400);
    }
}

void cc1101_send_slowrf(const char* hex_data) {
    cc1101_set_tx_mode();
    vTaskDelay(pdMS_TO_TICKS(2)); // Settling

    // Multi-transmit for reliability (standard culfw behavior)
    for (int repeat = 0; repeat < 3; repeat++) {
        // 1. Preamble (13 bits of 0)
        for(int i=0; i<13; i++) fs20_send_bit(0);

        // 2. Sync bit (bit 0)
        fs20_send_bit(0);

        // 3. Data (hex string to bits)
        int hex_len = strlen(hex_data);
        for(int i=0; i<hex_len; i+=2) {
            char h[3] = {hex_data[i], hex_data[i+1], 0};
            uint8_t b = (uint8_t)strtol(h, NULL, 16);
            int parity = 0;
            for(int j=7; j>=0; j--) {
                int bit = (b >> j) & 1;
                fs20_send_bit(bit);
                if (bit) parity++;
            }
            // FS20 uses ODD parity: number of 1-bits in the 9 bits must be odd.
            fs20_send_bit((parity % 2) ? 0 : 1);
        }

        // 4. End bit (bit 0)
        fs20_send_bit(0);

        // Gap between repeats
        ets_delay_us(10000);
    }

    cc1101_set_rx_mode();
}

esp_err_t cc1101_write_reg(uint8_t reg, uint8_t val) {
    spi_transaction_t t = {
        .length = 16,
        .tx_data = {reg, val},
        .flags = SPI_TRANS_USE_TXDATA
    };
    return spi_device_transmit(spi, &t);
}

esp_err_t cc1101_write_burst(uint8_t reg, const uint8_t *data, size_t len) {
    uint8_t tx_data[65];
    tx_data[0] = reg | CC1101_WRITE_BURST;
    memcpy(tx_data + 1, data, len);
    spi_transaction_t t = {
        .length = (len + 1) * 8,
        .tx_buffer = tx_data,
    };
    return spi_device_transmit(spi, &t);
}

uint8_t cc1101_read_reg(uint8_t reg) {
    uint8_t tx_data[2] = {reg | CC1101_READ_SINGLE, 0x00};
    uint8_t rx_data[2] = {0, 0};
    spi_transaction_t t = {
        .length = 16,
        .tx_buffer = tx_data,
        .rx_buffer = rx_data,
    };
    spi_device_transmit(spi, &t);
    return rx_data[1];
}

esp_err_t cc1101_cmd_strobe(uint8_t cmd) {
    spi_transaction_t t = {
        .length = 8,
        .tx_data = {cmd},
        .flags = SPI_TRANS_USE_TXDATA
    };
    return spi_device_transmit(spi, &t);
}

#include <stdio.h>
#include <string.h>
#include "freertos/FreeRTOS.h"
#include "freertos/task.h"
#include "culfw_parser.h"
#include "esp_log.h"
#include "esp_random.h"
#include "driver/gpio.h"
#include "driver/usb_serial_jtag.h"
#include "cc1101.h"
#include "slowrf.h"

static const char *TAG = "CULFW_PARSER";
static bool reporting_enabled = false;

bool culfw_reporting_enabled() {
    return reporting_enabled;
}

static void handle_command(char *cmd) {
    char out[128];
    int len = 0;
    if (cmd[0] == 'V') {
        bool is_433 = (gpio_get_level(GPIO_433MARKER) == 0);
        len = snprintf(out, sizeof(out), "V %s culfw-NG Build: %d (%s %s) CUL32-C6 (F-Band: %sMHz)\r\n", 
                       FW_VERSION, BUILD_NUMBER, __DATE__, __TIME__, is_433 ? "433" : "868");
    } else if (cmd[0] == 'X') {
        if (cmd[1] == '0' && cmd[2] == '0') {
            reporting_enabled = false;
            slowrf_set_debug(false);
        } else if (cmd[1] == '9' && cmd[2] == '9') {
            slowrf_set_debug(true);
            reporting_enabled = true;
        } else {
            reporting_enabled = true;
            slowrf_set_debug(false);
        }
        len = snprintf(out, sizeof(out), "X21\r\n");
    } else if (cmd[0] == 'C') {
        uint8_t part = cc1101_read_reg(CC1101_PARTNUM | CC1101_READ_BURST);
        uint8_t vers = cc1101_read_reg(CC1101_VERSION | CC1101_READ_BURST);
        uint8_t marc = cc1101_read_reg(0x35 | CC1101_READ_BURST);
        len = snprintf(out, sizeof(out), "C01 Part: 0x%02x, Vers: 0x%02x, MARC: 0x%02x\r\n", part, vers, marc);
    } else if (cmd[0] == 'F') {
        cc1101_send_slowrf(cmd + 1);
        len = snprintf(out, sizeof(out), "F OK\r\n");
    } else if (cmd[0] == 'T' && cmd[1] == 'r') {
        // Test Random: Send 5 random FS20 packets
        len = snprintf(out, sizeof(out), "Tr START\r\n");
        usb_serial_jtag_write_bytes(out, len, portMAX_DELAY);
        for (int i = 0; i < 5; i++) {
            char rnd_hex[11];
            uint32_t r = esp_random();
            // Just use the bytes directly for simplicity
            snprintf(rnd_hex, sizeof(rnd_hex), "%08X", r);

            char msg[64];
            int mlen = snprintf(msg, sizeof(msg), "TX: %s\r\n", rnd_hex);
            usb_serial_jtag_write_bytes(msg, mlen, portMAX_DELAY);

            cc1101_send_slowrf(rnd_hex);
            vTaskDelay(pdMS_TO_TICKS(500));
        }
        len = snprintf(out, sizeof(out), "Tr DONE\r\n");
    } else {
        len = snprintf(out, sizeof(out), "E %s unknown\r\n", cmd);
    }

    if (len > 0) {
        usb_serial_jtag_write_bytes(out, len, portMAX_DELAY);
    }
}

void culfw_parser_task(void *pvParameters) {
    // Check if driver is already installed (might be by another task or earlier boot stage)
    if (!usb_serial_jtag_is_driver_installed()) {
        usb_serial_jtag_driver_config_t usb_serial_jtag_config = USB_SERIAL_JTAG_DRIVER_CONFIG_DEFAULT();
        usb_serial_jtag_driver_install(&usb_serial_jtag_config);
    }

    uint8_t buf[128];
    char cmd_buf[128];
    int cmd_pos = 0;

    while (1) {
        int n = usb_serial_jtag_read_bytes(buf, sizeof(buf), pdMS_TO_TICKS(50));
        if (n > 0) {
            for (int i = 0; i < n; i++) {
                char c = (char)buf[i];
                if (c == '\r' || c == '\n') {
                    if (cmd_pos > 0) {
                        cmd_buf[cmd_pos] = '\0';
                        handle_command(cmd_buf);
                        cmd_pos = 0;
                    }
                } else if (cmd_pos < sizeof(cmd_buf) - 1) {
                    cmd_buf[cmd_pos++] = c;
                }
            }
        }
        vTaskDelay(pdMS_TO_TICKS(10));
    }
}

